import React, { useState } from 'react';

const App = () => {
  const [metrics, setMetrics] = useState([
    { id: 1, name: 'Metric 1', value: 1000 },
    { id: 2, name: 'Metric 2', value: 2000 },
    { id: 3, name: 'Metric 3', value: 3000 }
  ]);
  const [filter, setFilter] = useState({});

  const handleSort = (field) => {
    const sortedMetrics = [...metrics].sort((a, b) => a[field] - b[field]);
    setMetrics(sortedMetrics);
  };

  const handleFilter = (field, value) => {
    const filteredMetrics = metrics.filter((metric) => metric[field] === value);
    setMetrics(filteredMetrics);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      {/* Top bar -->
      <div className="bg-[#C06C88] p-2 mb-4">
        {/* Metric cards row -->
        <div className="bg-[#B7D7CD] p-2 mb-2">
          {/* Sorting and filtering controls -->
          <div className="bg-[#C06C88] p-2 mb-2">
            {/* Bottom padding -->
            <div className="bg-[#B7D7CD] p-2 mt-4">
            {/* Metric cards container -->
            <div className="flex flex-wrap justify-center mt-4">
              {metrics.map((metric) => (
                <div key={metric.id} className="bg-[#C06C88] p-2 mr-4 mb-4 w-32">
                  <text className="text-white font-bold mb-2">{metric.name}</text>
                  <text className="text-white">Value: {metric.value}</text>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
